import { Card, CardHeader, CardTitle, CardBody, Button } from "reactstrap";
import React from "react";

import { useHistory } from "react-router-dom";
import TableComponent from "../common/TableComponent";
import Badge from "reactstrap/lib/Badge";

export const taColumns = [
  {
    name: "Vessel name",
    selector: "vesselName",
    sortable: true,
    minWidth: "150px",
  },
  {
    name: "Vessel Number",
    selector: "vesselNo",
    sortable: true,
    minWidth: "150px",
  },
  {
    name: "Port Of Loading",
    selector: "portOfLoading",
    sortable: true,
    minWidth: "150px",
  },
  {
    name: "Status",
    selector: "VECHICAL_STATUS",
    sortable: true,
    minWidth: "150px",
    cell: (row) => {
      return (
        <Badge color={"light-success"} pill>
          {row.isApproved ? `Completed` : "Port Receipt"}
        </Badge>
      );
    },
  },
  {
    name: "Port Of Discharge",
    selector: "portOfDischarge",
    sortable: true,
    minWidth: "150px",
  },
];
const PortDispatchList = ({ title, url, actionRendorer }) => {
  const history = useHistory();

  const actionsCol = {
    name: "Actions",
    selector: "status",
    minWidth: "150px",
    cell: (row) => {
      return actionRendorer ? (
        actionRendorer(row)
      ) : (
        <Button.Ripple color="primary" onClick={() => onActionClick(row.id, row.isApproved)}>
          {row.isApproved ? `View` : "Approve"}
        </Button.Ripple>
      );
    },
  };
  const columns = [...taColumns, actionsCol];

  const onActionClick = (id, approved) => {
    if (!approved) {
      history.push("/IASRPRApprove/" + id);
    } else {
      history.push("/IASRPRView/" + id);
    }
  };

  return (
    <div>
      <Card>
        <CardHeader>
          <CardTitle>{title}</CardTitle>
        </CardHeader>
        <CardBody>
          <TableComponent columns={columns} url={url} formType="GetEntriesAtPort" />
        </CardBody>
      </Card>
    </div>
  );
};

export default PortDispatchList;
